document.addEventListener("DOMContentLoaded", function () {
  const switchEl = document.getElementById("pricing-switch");
  // On sélectionne uniquement les boutons :
  // - qui ont data-dynamic-link="pricing"
  // - ET un data-type non vide
  const buttons = document.querySelectorAll('[data-dynamic-link="pricing"][data-type]:not([data-type=""])');

  function getDuration() {
    // Si "toggled" est present => monthly
    return switchEl.classList.contains("toggled") ? "monthly" : "yearly";
  }

function updateLinks() {
